     1→const express = require('express');
     2→const bcrypt  = require('bcrypt');
     3→const jwt     = require('jsonwebtoken');
     4→const pool    = require('../db');
     5→const authMiddleware = require('../middleware/auth');
     6→
     7→const router = express.Router();
     8→const SECRET = process.env.JWT_SECRET || 'cortexbuild_secret';
     9→
    10→const VALID_ROLES = ['super_admin','company_owner','admin','project_manager','field_worker','client'];
    11→
    12→// POST /api/auth/register — public self-registration (creates company_owner account)
    13→router.post('/register', async (req, res) => {
    14→  const { name, email, password, company, phone } = req.body;
    15→
    16→  if (!name || !email || !password || !company) {
    17→    return res.status(400).json({ message: 'Name, email, password and company are required' });
    18→  }
    19→  if (password.length < 8) {
    20→    return res.status(400).json({ message: 'Password must be at least 8 characters' });
    21→  }
    22→  const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    23→  if (!emailRe.test(email)) {
    24→    return res.status(400).json({ message: 'Invalid email address' });
    25→  }
    26→
    27→  try {
    28→    // Check for duplicate email
    29→    const existing = await pool.query('SELECT id FROM users WHERE email = $1', [email.toLowerCase().trim()]);
    30→    if (existing.rows.length) {
    31→      return res.status(409).json({ message: 'An account with that email already exists' });
    32→    }
    33→
    34→    const hash = await bcrypt.hash(password, 10);
    35→    const { rows } = await pool.query(
    36→      `INSERT INTO users (name, email, password_hash, role, company, phone)
    37→       VALUES ($1, $2, $3, 'company_owner', $4, $5)
    38→       RETURNING id, name, email, role, company, phone, created_at`,
    39→      [name.trim(), email.toLowerCase().trim(), hash, company.trim(), phone || null]
    40→    );
    41→    const newUser = rows[0];
    42→
    43→    const token = jwt.sign(
    44→      { id: newUser.id, email: newUser.email, role: newUser.role, name: newUser.name, company: newUser.company },
    45→      SECRET,
    46→      { expiresIn: '7d' }
    47→    );
    48→
    49→    res.status(201).json({ token, user: newUser });
    50→  } catch (err) {
    51→    console.error('[auth/register]', err);
    52→    res.status(500).json({ message: 'Server error during registration' });
    53→  }
    54→});
    55→
    56→// POST /api/auth/login
    57→router.post('/login', async (req, res) => {
    58→  const { email, password } = req.body;
    59→  if (!email || !password) return res.status(400).json({ message: 'Email and password required' });
    60→
    61→  try {
    62→    const { rows } = await pool.query('SELECT * FROM users WHERE email = $1', [email.toLowerCase().trim()]);
    63→    const user = rows[0];
    64→    if (!user) return res.status(401).json({ message: 'Invalid email or password' });
    65→
    66→    const valid = await bcrypt.compare(password, user.password_hash);
    67→    if (!valid) return res.status(401).json({ message: 'Invalid email or password' });
    68→
    69→    const token = jwt.sign(
    70→      { id: user.id, email: user.email, role: user.role, name: user.name, company: user.company },
    71→      SECRET,
    72→      { expiresIn: '7d' }
    73→    );
    74→
    75→    const { password_hash, ...safeUser } = user;
    76→    res.json({ token, user: safeUser });
    77→  } catch (err) {
    78→    console.error('[auth/login]', err);
    79→    res.status(500).json({ message: 'Server error' });
    80→  }
    81→});
    82→
    83→// GET /api/auth/me
    84→router.get('/me', authMiddleware, async (req, res) => {
    85→  try {
    86→    const { rows } = await pool.query(
    87→      'SELECT id,name,email,role,company,phone,avatar,created_at FROM users WHERE id = $1',
    88→      [req.user.id]
    89→    );
    90→    if (!rows[0]) return res.status(404).json({ message: 'User not found' });
    91→    res.json(rows[0]);
    92→  } catch (err) {
    93→    res.status(500).json({ message: 'Server error' });
    94→  }
    95→});
    96→
    97→// PUT /api/auth/profile
    98→router.put('/profile', authMiddleware, async (req, res) => {
    99→  const { name, phone } = req.body;
   100→  try {
   101→    const { rows } = await pool.query(
   102→      'UPDATE users SET name=$1, phone=$2 WHERE id=$3 RETURNING id,name,email,role,company,phone,avatar',
   103→      [name, phone, req.user.id]
   104→    );
   105→    res.json(rows[0]);
   106→  } catch (err) {
   107→    res.status(500).json({ message: 'Server error' });
   108→  }
   109→});
   110→
   111→// PUT /api/auth/password
   112→router.put('/password', authMiddleware, async (req, res) => {
   113→  const { currentPassword, newPassword } = req.body;
   114→  if (!currentPassword || !newPassword) return res.status(400).json({ message: 'Both passwords required' });
   115→  if (newPassword.length < 8) return res.status(400).json({ message: 'Password must be at least 8 characters' });
   116→
   117→  try {
   118→    const { rows } = await pool.query('SELECT * FROM users WHERE id = $1', [req.user.id]);
   119→    const user = rows[0];
   120→    const valid = await bcrypt.compare(currentPassword, user.password_hash);
   121→    if (!valid) return res.status(400).json({ message: 'Current password is incorrect' });
   122→
   123→    const hash = await bcrypt.hash(newPassword, 10);
   124→    await pool.query('UPDATE users SET password_hash=$1 WHERE id=$2', [hash, req.user.id]);
   125→    res.json({ message: 'Password updated successfully' });
   126→  } catch (err) {
   127→    res.status(500).json({ message: 'Server error' });
   128→  }
   129→});
   130→
   131→// GET /api/auth/users — list all users (admin+ only)
   132→router.get('/users', authMiddleware, async (req, res) => {
   133→  if (!['super_admin','company_owner','admin'].includes(req.user.role)) {
   134→    return res.status(403).json({ message: 'Insufficient permissions' });
   135→  }
   136→  try {
   137→    const { rows } = await pool.query(
   138→      'SELECT id,name,email,role,company,phone,avatar,created_at FROM users ORDER BY created_at DESC'
   139→    );
   140→    res.json(rows);
   141→  } catch (err) {
   142→    res.status(500).json({ message: 'Server error' });
   143→  }
   144→});
   145→
   146→// POST /api/auth/users — create user (admin+ only)
   147→router.post('/users', authMiddleware, async (req, res) => {
   148→  if (!['super_admin','company_owner','admin'].includes(req.user.role)) {
   149→    return res.status(403).json({ message: 'Insufficient permissions' });
   150→  }
   151→
   152→  const { name, email, password, role = 'project_manager', company, phone } = req.body;
   153→  if (!name || !email || !password) return res.status(400).json({ message: 'Name, email, and password are required' });
   154→  if (password.length < 8) return res.status(400).json({ message: 'Password must be at least 8 characters' });
   155→  if (!VALID_ROLES.includes(role)) return res.status(400).json({ message: `Invalid role. Must be one of: ${VALID_ROLES.join(', ')}` });
   156→
   157→  try {
   158→    const hash = await bcrypt.hash(password, 10);
   159→    const { rows } = await pool.query(
   160→      'INSERT INTO users (name,email,password_hash,role,company,phone) VALUES ($1,$2,$3,$4,$5,$6) RETURNING id,name,email,role,company,phone,created_at',
   161→      [name, email.toLowerCase().trim(), hash, role, company || 'CortexBuild Ltd', phone || null]
   162→    );
   163→    res.status(201).json(rows[0]);
   164→  } catch (err) {
   165→    if (err.code === '23505') return res.status(409).json({ message: 'Email already in use' });
   166→    console.error('[auth/users POST]', err);
   167→    res.status(500).json({ message: 'Server error' });
   168→  }
   169→});
   170→
   171→// DELETE /api/auth/users/:id — delete user (super_admin / company_owner only)
   172→router.delete('/users/:id', authMiddleware, async (req, res) => {
   173→  if (!['super_admin','company_owner'].includes(req.user.role)) {
   174→    return res.status(403).json({ message: 'Insufficient permissions' });
   175→  }
   176→  if (req.params.id === req.user.id) return res.status(400).json({ message: 'Cannot delete your own account' });
   177→
   178→  try {
   179→    const { rowCount } = await pool.query('DELETE FROM users WHERE id = $1', [req.params.id]);
   180→    if (!rowCount) return res.status(404).json({ message: 'User not found' });
   181→    res.json({ message: 'User deleted' });
   182→  } catch (err) {
   183→    res.status(500).json({ message: 'Server error' });
   184→  }
   185→});
   186→
   187→// PUT /api/auth/avatar
   188→router.put('/avatar', authMiddleware, async (req, res) => {
   189→  const { avatar } = req.body;
   190→  if (!avatar) return res.status(400).json({ message: 'Avatar URL required' });
   191→  try {
   192→    const { rows } = await pool.query(
   193→      'UPDATE users SET avatar=$1 WHERE id=$2 RETURNING id,name,email,role,company,phone,avatar',
   194→      [avatar, req.user.id]
   195→    );
   196→    res.json(rows[0]);
   197→  } catch (err) {
   198→    res.status(500).json({ message: 'Server error' });
   199→  }
   200→});
   201→
   202→// GET /api/auth/settings — get all user settings
   203→router.get('/settings', authMiddleware, async (req, res) => {
   204→  try {
   205→    const { rows } = await pool.query(
   206→      'SELECT key, value FROM app_settings WHERE user_id=$1',
   207→      [req.user.id]
   208→    );
   209→    const settings = Object.fromEntries(rows.map(r => [r.key, r.value]));
   210→    res.json(settings);
   211→  } catch (err) {
   212→    res.status(500).json({ message: 'Server error' });
   213→  }
   214→});
   215→
   216→// PUT /api/auth/settings — upsert a setting key
   217→router.put('/settings', authMiddleware, async (req, res) => {
   218→  const { key, value } = req.body;
   219→  if (!key) return res.status(400).json({ message: 'key required' });
   220→  try {
   221→    await pool.query(
   222→      `INSERT INTO app_settings (user_id, key, value)
   223→       VALUES ($1, $2, $3::jsonb)
   224→       ON CONFLICT (user_id, key) DO UPDATE SET value=$3::jsonb, updated_at=now()`,
   225→      [req.user.id, key, JSON.stringify(value)]
   226→    );
   227→    res.json({ key, value });
   228→  } catch (err) {
   229→    res.status(500).json({ message: 'Server error' });
   230→  }
   231→});
   232→
   233→module.exports = router;
   234→

