     1→/**
     2→ * CortexBuild Ultimate — WebSocket Server
     3→ * Real-time notifications, live dashboard updates, collaborative features
     4→ */
     5→
     6→const WebSocket = require('ws');
     7→const jwt = require('jsonwebtoken');
     8→
     9→const JWT_SECRET = process.env.JWT_SECRET || 'cortexbuild-secret-key';
    10→
    11→// Message types
    12→const MESSAGE_TYPES = {
    13→  NOTIFICATION: 'notification',
    14→  DASHBOARD_UPDATE: 'dashboard_update',
    15→  ALERT: 'alert',
    16→  COLLABORATION: 'collaboration',
    17→  SYSTEM: 'system',
    18→};
    19→
    20→// Connection store
    21→const clients = new Map(); // Map<userId, Set<WebSocket>>
    22→const rooms = new Map();   // Map<roomId, Set<userId>>
    23→
    24→/**
    25→ * Initialize WebSocket server
    26→ * @param {http.Server} server - HTTP server to attach to
    27→ */
    28→function initWebSocket(server) {
    29→  const wss = new WebSocket.Server({ server, path: '/ws' });
    30→
    31→  wss.on('connection', (ws, req) => {
    32→    console.log('[WS] New connection');
    33→
    34→    // Authenticate connection
    35→    const token = extractToken(req.url);
    36→    if (!token || !verifyToken(token)) {
    37→      ws.close(4001, 'Unauthorized');
    38→      return;
    39→    }
    40→
    41→    const userId = decodeToken(token).id;
    42→    const userRooms = new Set();
    43→
    44→    // Register client
    45→    if (!clients.has(userId)) {
    46→      clients.set(userId, new Set());
    47→    }
    48→    clients.get(userId).add(ws);
    49→
    50→    // Auto-join user's personal room
    51→    userRooms.add(`user:${userId}`);
    52→    joinRoom(userId, `user:${userId}`);
    53→
    54→    // Handle messages
    55→    ws.on('message', (data) => {
    56→      try {
    57→        const message = JSON.parse(data.toString());
    58→        handleMessage(ws, userId, message);
    59→      } catch (err) {
    60→        console.error('[WS] Message parse error:', err.message);
    61→        sendError(ws, 'Invalid message format');
    62→      }
    63→    });
    64→
    65→    // Handle connection close
    66→    ws.on('close', () => {
    67→      console.log('[WS] Connection closed');
    68→      clients.get(userId)?.delete(ws);
    69→      if (clients.get(userId)?.size === 0) {
    70→        clients.delete(userId);
    71→      }
    72→      // Leave all rooms
    73→      userRooms.forEach(room => leaveRoom(userId, room));
    74→    });
    75→
    76→    // Send welcome message
    77→    sendToClient(ws, {
    78→      type: MESSAGE_TYPES.SYSTEM,
    79→      event: 'connected',
    80→      payload: {
    81→        message: 'Connected to CortexBuild real-time service',
    82→        timestamp: new Date().toISOString(),
    83→      },
    84→    });
    85→  });
    86→
    87→  console.log('[WS] WebSocket server initialized on /ws');
    88→  return wss;
    89→}
    90→
    91→/**
    92→ * Extract JWT token from WebSocket URL query string
    93→ */
    94→function extractToken(url) {
    95→  const urlObj = new URL(url, 'ws://localhost');
    96→  return urlObj.searchParams.get('token');
    97→}
    98→
    99→/**
   100→ * Verify JWT token
   101→ */
   102→function verifyToken(token) {
   103→  try {
   104→    jwt.verify(token, JWT_SECRET);
   105→    return true;
   106→  } catch (err) {
   107→    console.error('[WS] Token verification failed');
   108→    return false;
   109→  }
   110→}
   111→
   112→/**
   113→ * Decode JWT token
   114→ */
   115→function decodeToken(token) {
   116→  return jwt.decode(token);
   117→}
   118→
   119→/**
   120→ * Send message to specific client
   121→ */
   122→function sendToClient(ws, message) {
   123→  if (ws.readyState === WebSocket.OPEN) {
   124→    ws.send(JSON.stringify(message));
   125→  }
   126→}
   127→
   128→/**
   129→ * Send message to all clients of a user
   130→ */
   131→function sendToUser(userId, message) {
   132→  const userClients = clients.get(userId);
   133→  if (userClients) {
   134→    userClients.forEach(ws => sendToClient(ws, message));
   135→  }
   136→}
   137→
   138→/**
   139→ * Send message to room
   140→ */
   141→function sendToRoom(roomId, message, excludeUserId = null) {
   142→  const room = rooms.get(roomId);
   143→  if (room) {
   144→    room.forEach(userId => {
   145→      if (userId !== excludeUserId) {
   146→        sendToUser(userId, message);
   147→      }
   148→    });
   149→  }
   150→}
   151→
   152→/**
   153→ * Broadcast to all connected clients
   154→ */
   155→function broadcast(message) {
   156→  clients.forEach((userClients, userId) => {
   157→    userClients.forEach(ws => sendToClient(ws, message));
   158→  });
   159→}
   160→
   161→/**
   162→ * Join room
   163→ */
   164→function joinRoom(userId, roomId) {
   165→  if (!rooms.has(roomId)) {
   166→    rooms.set(roomId, new Set());
   167→  }
   168→  rooms.get(roomId).add(userId);
   169→}
   170→
   171→/**
   172→ * Leave room
   173→ */
   174→function leaveRoom(userId, roomId) {
   175→  const room = rooms.get(roomId);
   176→  if (room) {
   177→    room.delete(userId);
   178→    if (room.size === 0) {
   179→      rooms.delete(roomId);
   180→    }
   181→  }
   182→}
   183→
   184→/**
   185→ * Handle incoming message
   186→ */
   187→function handleMessage(ws, userId, message) {
   188→  const { type, event, payload, room } = message;
   189→
   190→  switch (event) {
   191→    case 'join_room':
   192→      joinRoom(userId, payload.room);
   193→      sendToClient(ws, {
   194→        type: MESSAGE_TYPES.SYSTEM,
   195→        event: 'room_joined',
   196→        payload: { room: payload.room },
   197→      });
   198→      break;
   199→
   200→    case 'leave_room':
   201→      leaveRoom(userId, payload.room);
   202→      sendToClient(ws, {
   203→        type: MESSAGE_TYPES.SYSTEM,
   204→        event: 'room_left',
   205→        payload: { room: payload.room },
   206→      });
   207→      break;
   208→
   209→    case 'send_notification':
   210→      // Send notification to specific user or room
   211→      if (payload.userId) {
   212→        sendToUser(payload.userId, {
   213→          type: MESSAGE_TYPES.NOTIFICATION,
   214→          event: 'notification',
   215→          payload: {
   216→            from: userId,
   217→            ...payload.data,
   218→            timestamp: new Date().toISOString(),
   219→          },
   220→        });
   221→      } else if (payload.room) {
   222→        sendToRoom(payload.room, {
   223→          type: MESSAGE_TYPES.NOTIFICATION,
   224→          event: 'notification',
   225→          payload: {
   226→            from: userId,
   227→            ...payload.data,
   228→            timestamp: new Date().toISOString(),
   229→          },
   230→        });
   231→      }
   232→      break;
   233→
   234→    case 'broadcast':
   235→      broadcast({
   236→        type: MESSAGE_TYPES.SYSTEM,
   237→        event: 'broadcast',
   238→        payload: {
   239→          from: userId,
   240→          ...payload,
   241→          timestamp: new Date().toISOString(),
   242→        },
   243→      });
   244→      break;
   245→
   246→    default:
   247→      sendError(ws, `Unknown event: ${event}`);
   248→  }
   249→}
   250→
   251→/**
   252→ * Send error message
   253→ */
   254→function sendError(ws, errorMessage) {
   255→  sendToClient(ws, {
   256→    type: MESSAGE_TYPES.SYSTEM,
   257→    event: 'error',
   258→    payload: { message: errorMessage },
   259→  });
   260→}
   261→
   262→/**
   263→ * Create notification helper
   264→ */
   265→function createNotification(userId, title, description, severity = 'info', data = {}) {
   266→  sendToUser(userId, {
   267→    type: MESSAGE_TYPES.NOTIFICATION,
   268→    event: 'notification',
   269→    payload: {
   270→      title,
   271→      description,
   272→      severity,
   273→      ...data,
   274→      timestamp: new Date().toISOString(),
   275→    },
   276→  });
   277→}
   278→
   279→/**
   280→ * Create alert helper (high priority notification)
   281→ */
   282→function createAlert(userId, title, description, data = {}) {
   283→  sendToUser(userId, {
   284→    type: MESSAGE_TYPES.ALERT,
   285→    event: 'alert',
   286→    payload: {
   287→      title,
   288→      description,
   289→      priority: 'high',
   290→      ...data,
   291→      timestamp: new Date().toISOString(),
   292→    },
   293→  });
   294→}
   295→
   296→/**
   297→ * Dashboard update helper
   298→ */
   299→function sendDashboardUpdate(userId, updates) {
   300→  sendToUser(userId, {
   301→    type: MESSAGE_TYPES.DASHBOARD_UPDATE,
   302→    event: 'dashboard_update',
   303→    payload: {
   304→      updates,
   305→      timestamp: new Date().toISOString(),
   306→    },
   307→  });
   308→}
   309→
   310→/**
   311→ * Project room helpers
   312→ */
   313→function createProjectRoom(projectId, userId) {
   314→  joinRoom(userId, `project:${projectId}`);
   315→}
   316→
   317→function notifyProjectTeam(projectId, title, description, excludeUserId = null) {
   318→  sendToRoom(`project:${projectId}`, {
   319→    type: MESSAGE_TYPES.COLLABORATION,
   320→    event: 'project_notification',
   321→    payload: {
   322→      projectId,
   323→      title,
   324→      description,
   325→      timestamp: new Date().toISOString(),
   326→    },
   327→  }, excludeUserId);
   328→}
   329→
   330→// Export for use in routes
   331→module.exports = {
   332→  initWebSocket,
   333→  createNotification,
   334→  createAlert,
   335→  sendDashboardUpdate,
   336→  createProjectRoom,
   337→  notifyProjectTeam,
   338→  broadcast,
   339→  MESSAGE_TYPES,
   340→};
