     5→// ─── Animated counter hook ─────────────────────────────────────────────────
     6→function useCounter(target: number, duration = 1800, startDelay = 0) {
     7→  const [val, setVal] = useState(0);
     8→  useEffect(() => {
     9→    const t = setTimeout(() => {
    10→      const start = performance.now();
    11→      const tick = (now: number) => {
    12→        const p = Math.min((now - start) / duration, 1);
    13→        const eased = 1 - Math.pow(1 - p, 3);
    14→        setVal(Math.round(eased * target));
    15→        if (p < 1) requestAnimationFrame(tick);
    16→      };
    17→      requestAnimationFrame(tick);
    18→    }, startDelay);
    19→    return () => clearTimeout(t);
    20→  }, [target, duration, startDelay]);
    21→  return val;
    22→}
